import Foundation

enum LogLevel {
    case debug
    case info
    case warning
    case error
}

class AnalyticsLogger {
    static let shared = AnalyticsLogger()
    
    private init() {}
    
    func log(_ message: String, level: LogLevel) {
        switch level {
        case .debug:
            #if DEBUG
            print(message)
            #endif
        case .info:
            NSLog("INFO: \(message)")
        case .warning:
            NSLog("WARNING: \(message)")
        case .error:
            NSLog("ERROR: \(message)")
        }
    }
    
    func logUserInteraction(_ interaction: String, userID: String) {
        log("User Interaction: \(interaction), UserID: \(userID)", level: .info)
    }
    
    func logAPIRequest(_ endpoint: String, method: String, parameters: [String: Any]?) {
        let params = parameters?.map { "\($0.key): \($0.value)" }.joined(separator: ", ")
        log("API Request: \(method) \(endpoint), Params: \(params ?? "nil")", level: .debug)
    }
    
    func logAPISuccess(_ endpoint: String, response: Any?) {
        log("API Success: \(endpoint), Response: \(String(describing: response))", level: .info)
    }
    
